INSERT INTO vehicles (id, year, make, model, external_id, content_source) VALUES ('4f0574a5-9de9-417d-bfea-915c98f56f73', 2009, 'Suzuki', 'Equator Base', '54406:2600', 'MOTOR');
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('da07a35c-5c16-483b-a395-b9919c84a41c', '4f0574a5-9de9-417d-bfea-915c98f56f73', 'ABS Deceleration Sensor Calibrate', 'P:565148915', NULL, '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Deceleration Sensor Calibrate</h2>\n<p>Calibration of the decel G sensor is required when, replacing ABS actuator and electric unit (control unit), removing and installing or replacing steering angle sensor, replacing steering components, removing and installing or replacing suspension components, and adjusting wheel alignment.</p>\n<ol type=\"1\">\n  <li>Stop vehicle with front wheels in straight-ahead position.</li>\n  <li>On a suitably programmed scan tool screen, touch WORK SUPPORT and DECEL G SEN CALIBRATION in order.</li>\n  <li>Touch START.</li>\n  <li>After approximately 10 seconds, touch END. After approximately 60 seconds, it ends automatically.</li>\n  <li>Turn ignition switch OFF, then turn ignition ON again.</li>\n  <li>Run vehicle with front wheels in straight-ahead position, then stop.</li>\n  <li>Select DATA MONITOR. Then make sure DECEL G SEN is within ± .08G.</li>\n  <li>If inspection result for DECEL G SEN is NOT normal, repeat steps 1 through 7.<"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('52ff6311-6366-4efd-84ea-d85b5a9b4a17', '4f0574a5-9de9-417d-bfea-915c98f56f73', 'ABS Hydraulic Control Unit', 'P:551732842', NULL, '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Hydraulic Control Unit</h2>\n<p>Vehicle Dynamics Control (VDC) system detects driver''s steering operation amount and brake pedal travel from steering angle sensor and pressure sensors. Using information from yaw rate/side/decel G sensor and wheel sensor, VDC judges driving conditions of under steer and over steer, to improve vehicle driving stability by controlling brake application to four wheels and engine output.</p>\n<p>During VDC operation, it informs driver of system operation by flashing SLIP indicator lamp.</p>\n<p>VDC warning lamp and SLIP indicator lamp may turn on when driving on roads, which have extreme slopes such as mountainous roads or high banks such as sharp curves on a freeway. When TCS or VDC is activated by sudden acceleration or sudden turn, some noise may occur. The noise is a result of the normal operation of TCS and VDC. This is not a problem, if normal operation can be resumed after restarting engine.</p>\n<p>Steering angle sensor d"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('b46cc5a8-2f3d-42f0-874a-2e69c6af06f8', '4f0574a5-9de9-417d-bfea-915c98f56f73', 'ABS Hydraulic Control Unit R&R', 'P:543637000', 'Component Replacement', '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Hydraulic Control Unit R&R</h2>\n<ol type=\"1\">\n  <li>Disconnect negative battery terminal.</li>\n  <li>Drain brake fluid into suitable container.</li>\n  <li>Remove air cleaner case, <div style=\"display:block; width:500px; padding:10px; text-align:center; margin:auto\"><image class=''img-fluid img-thumbnail'' style=''max-height: 600px; margin: 30px;'' src=''api/source/MOTOR/graphic/12785181''></image><b>Fig. IRM0900000011591.</b></div>\n  </li>\n  <li>Disconnect ABS control module electrical connector.</li>\n  <li>Loosen flare nuts, then disconnect brake tubes from ABS control module using special tool 09950-78220 or equivalent, <div style=\"display:block; width:500px; padding:10px; text-align:center; margin:auto\"><image class=''img-fluid img-thumbnail'' style=''max-height: 600px; margin: 30px;'' src=''api/source/MOTOR/graphic/12785182''></image><b>Fig. IRM0900000011592.</b></div>\n  </li>\n  <li>Remove three ABS control module attaching bolts, then remove module, <div style="}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('0e9c684b-6d02-4f26-a95c-f22d1f44ce05', '4f0574a5-9de9-417d-bfea-915c98f56f73', 'ABS Hydraulic Control Unit R&R', 'P:543637001', 'Component Replacement', '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Hydraulic Control Unit R&R</h2>\n<ol type=\"1\">\n  <li>Remove battery ground cable from battery.</li>\n  <li>Remove air duct and resonator assembly and air cleaner case.</li>\n  <li>Drain brake fluid As described under <q>Drain and Refill.</q></li>\n  <li>Disconnect actuator harness connector from ABS actuator and electric unit, <div style=\"display:block; width:500px; padding:10px; text-align:center; margin:auto\"><image class=''img-fluid img-thumbnail'' style=''max-height: 600px; margin: 30px;'' src=''api/source/MOTOR/graphic/14297937''></image><b>Fig. ESC1100000001226.</b></div>\n  </li>\n  <li>Disconnect brake tubes.</li>\n  <li>Remove three bolts and remove ABS actuator and electric unit.</li>\n  <li>Reverse procedure to install, noting the following:</li>\n  <ol type=\"a\">\n    <li><b>Torque</b> three ABS actuator and electric unit bolts to 15 ft. lbs.</li>\n    <li><b>Torque</b> caliper brake tubes to 120 inch lbs.</li>\n    <li><b>Torque</b> master cylinder brake tubes"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('edc70027-9182-4464-8429-ae51295d08b0', '4f0574a5-9de9-417d-bfea-915c98f56f73', 'ABS System Diagnosis & Testing', 'P:550880901', NULL, '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS System Diagnosis & Testing</h2>\n<p>Fluid leakage from brake lines and/or hoses.</p>\n<p>Brake disc or pads stained with fluid.</p>\n<p>Overheated brakes.</p>\n<p>Poor contact of shoes on brake drum.</p>\n<p>Brake shoe linings stained with fluid or wet with water.</p>\n<p>Badly worn brake shoe linings.</p>\n<p>Defective wheel cylinder and/or caliper assembly.</p>\n<p>Air in brake system.</p>\n<p>Faulty ABS system, if equipped.</p>\n<p>Pad or shoe linings are wet with water or stained with fluid in some brakes.</p>\n<p>Drum to shoe clearance out of adjustment in some brakes (faulty auto adjusting mechanism).</p>\n<p>Drum is out of round in some brakes.</p>\n<p>Wheel tires are inflated unequally.</p>\n<p>Defective wheel cylinder and/or caliper assembly.</p>\n<p>Disturbed front end alignment.</p>\n<p>Unmatched tires on same axle.</p>\n<p>Restricted brake pipes or hoses.</p>\n<p>Faulty caliper assembly.</p>\n<p>Loose suspension components.</p>\n<p>Loose calipers.</p>\n<p>Partial"}]', NULL);
