INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('ee6e8c2d-137b-49ca-b5cc-d19c82092e8b', 'd74f5995-7bae-4bec-bcc2-6b70afc9aa99', 'ABS Acceleration Sensor R&R', 'P:563906015', 'With Stability Control', '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Acceleration Sensor R&R</h2>\n<p>Prior to service, disconnect battery ground cable and isolate as required.</p>"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('bdaebee8-1a5c-43b9-bea1-4cb639b9254d', 'd74f5995-7bae-4bec-bcc2-6b70afc9aa99', 'ABS Control Module R&R', 'P:562318667', 'Without Traction Control, Mark II', '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Control Module R&R</h2>\n<p>Prior to service, disconnect battery ground cable and isolate as required.</p>"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('c95cdeaa-b49e-4e4f-a930-490066582c70', 'd74f5995-7bae-4bec-bcc2-6b70afc9aa99', 'ABS Control Module Relearn', 'P:564662106', NULL, '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Control Module Relearn</h2>\n<p>The Porsche System Tester must be used to calibrate hydraulic unit and control unit.</p>\n<ol type=\"1\">\n  <li>Connect Porsche System Tester to DLC.</li>\n  <li>Read out data from old hydraulic unit/control unit.</li>\n  <li>Switch ignition off.</li>\n  <li>Pull off connector for hydraulic unit and connect connector to new hydraulic unit.</li>\n  <li>Switch on ignition.</li>\n  <li>Transfer data.</li>\n  <li>Disconnect Porsche System Tester from DLC.</li>\n</ol>"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('0510ce56-f2fe-40d7-9051-d05c5f4734a3', 'd74f5995-7bae-4bec-bcc2-6b70afc9aa99', 'ABS Control Module Relearn', 'P:564673647', 'With Stability Control', '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Control Module Relearn</h2>\n<p>If hydraulic unit is replaced, PSM control unit must be coded using Porsche System Tester. Hydraulic unit and PSM control unit form one unit.</p>\n<p>The Porsche System Tester must not be disconnected from diagnostic socket when replacing hydraulic unit.</p>\n<ol type=\"1\">\n  <li>Tun ignition ON.</li>\n  <li>Read data from old hydraulic unit/control unit.</li>\n  <li>Turn ignition OFF.</li>\n  <li>Disconnect connector from hydraulic unit and connect connector to new hydraulic unit.</li>\n  <li>Turn ignition ON.</li>\n  <li>Transfer data.</li>\n</ol>"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('4746e650-23c8-4e92-8b11-f74095ddd942', 'd74f5995-7bae-4bec-bcc2-6b70afc9aa99', 'ABS Hydraulic Control Unit', 'P:551732936', NULL, '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Hydraulic Control Unit</h2>\n<p>The multi-functional information light on instrument panel flashes and hydraulic noises can be heard during PSM operation. The vehicle decelerates, engine power is reduced and, steering-wheel forces are altered as PSM controls the brakes. The brake pedal pulsates and its position is changed during braking. In order to achieve full vehicle deceleration, foot pressure must be increased after brake pedal has begun vibrating.</p>"}]', NULL);
