INSERT INTO vehicles (id, year, make, model, external_id, content_source) VALUES ('33011d6b-1af8-4142-b3e8-426566bd06f0', 2009, 'Hyundai', 'Accent GLS', '54145:3025', 'MOTOR');
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('56208171-9a01-43fe-bbf1-5ac7fa6cf151', '33011d6b-1af8-4142-b3e8-426566bd06f0', 'ABS Control Module R&R', 'P:539621349', NULL, '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Control Module R&R</h2>\n<ol type=\"1\">\n  <li>Remove air-cleaner and intake hose.</li>\n  <li><b>On Santa Fe models, </b>remove ECM (Engine Control Module).</li>\n  <li><b>On all models, </b>disconnect double lock connector from HECU.</li>\n  <li>Disconnect brake tubes from HECU.</li>\n  <li>Remove HECU bracket mounting bolts and remove HECU. Never attempt to disassemble HECU. HECU must be transported and stored in an upright position and with ports sealed. HECU must not be drained.</li>\n  <li>Reverse procedure to install, noting the following:</li>\n  <ol type=\"a\">\n    <li><b>On Accent and Sonata models torque </b> bracket mounting bolts to 72 to 84 inch lbs.</li>\n    <li><b>On Azera, Elantra, Entourage, Santa Fe, Tiburon, Tucson and Veracruz models torque </b> bracket mounting bolts to 12 to 19 ft. lbs.</li>\n  </ol>\n</ol>"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('9ab28d8a-27af-434c-bebd-3a26619f2144', '33011d6b-1af8-4142-b3e8-426566bd06f0', 'ABS Control Module R&R', 'P:562318482', 'Without Traction Control, Mark II', '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Control Module R&R</h2>\n<p>Prior to service, disconnect battery ground cable and isolate as required.</p>"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('34de001c-0dae-4397-ac11-43835b6e5cb8', '33011d6b-1af8-4142-b3e8-426566bd06f0', 'ABS Hydraulic Control Unit R&R', 'P:562942355', 'Without Traction Control, Mark II', '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Hydraulic Control Unit R&R</h2>\n<p>Prior to service, disconnect battery ground cable and isolate as required.</p>"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('67c04557-5c7e-4789-9ddd-088d5bf1a528', '33011d6b-1af8-4142-b3e8-426566bd06f0', 'ABS System Inspect', 'P:554431031', NULL, '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS System Inspect</h2>\n<p>A visual inspection must always be performed to confirm the presence of aftermarket components, potential collision damage, or areas of concern.</p>\n<p>The ABS module is self monitoring. The module will carry out a preliminary electrical inspection of the hydraulic pump motor by turning the pump ON for approximately <sup>1/2</sup> second either when the ignition switch is turned to the RUN position and the brake pedal is not pressed or when the vehicle is in motion and at vehicle speeds above 12 mph. The ABS module will also carry out a wheel speed sensor self-test by sending a reference voltage to all of the wheel speed sensors through their circuitry when the ignition switch is turned to the RUN position, with or without brake pedal application. If a fault is detected in the pump or wheel speed sensors, the ABS module will shut down and disable the anti-lock system. Normal power assisted braking, however, remains.</p>\n<ol type=\"1"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('993fbfb1-b8bd-4ec0-bbca-9ee88b84cd76', '33011d6b-1af8-4142-b3e8-426566bd06f0', 'ABS Warning Lamp Reset', 'P:564692217', NULL, '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Warning Lamp Reset</h2>\n<p>Anti-Lock warning lamp is used to warn of a system fault. It will be lit during engine start up, but should go out when self diagnostic system determines that system is functioning properly. If lamp remains lit, a fault in anti-lock brake system is indicated. Following diagnosis and repair of system, lamp may be turned off using a suitably programmed scan tool. Follow tool manufacturer instructions.</p>"}]', NULL);
