INSERT INTO vehicles (id, year, make, model, external_id, content_source) VALUES ('59914b93-2d1a-4426-b22c-654d24866081', 2009, 'BMW', '128i Base', '53947:3525', 'MOTOR');
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('d18645c1-dd9b-4632-abb5-57a76bc54097', '59914b93-2d1a-4426-b22c-654d24866081', 'ABS Control Module R&R', 'P:539621036', 'Component Replacement', '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Control Module R&R</h2>\n<ol type=\"1\">\n  <li>As required, remove hydraulic control unit.</li>\n  <li>Disconnect control unit electrical connector.</li>\n  <li>Remove mounting bolts and control module.</li>\n  <li>Reverse procedure to install.</li>\n  <ol type=\"a\">\n    <li>If hydraulic unit was removed, bleed brakes as outlined in <q>Brake System Bleed.</q></li>\n    <li>Refer to <q>Control Module Programming</q> for hydraulic control unit module programming procedure.</li>\n    <li>Refer to <q>Control Module Programming</q> for steering angle sensor programming procedure.</li>\n  </ol>\n</ol>"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('c32df399-fd26-4766-9691-6fe9894777ba', '59914b93-2d1a-4426-b22c-654d24866081', 'ABS Control Module R&R', 'P:539621037', 'Component Replacement', '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Control Module R&R</h2>\n<ol type=\"1\">\n  <li>Disconnect battery ground cable.</li>\n  <li>Remove hydraulic unit as outlined under <q>Hydraulic Unit.</q> Removing pump motor from valve block is not permitted.</li>\n  <li>Close off pipe connections with plugs.</li>\n  <li>Remove screws from control unit, <div style=\"display:block; width:500px; padding:10px; text-align:center; margin:auto\"><image class=''img-fluid img-thumbnail'' style=''max-height: 600px; margin: 30px;'' src=''api/source/MOTOR/graphic/14351359''></image><b>Fig. ESC1100000003274.</b></div>\n  </li>\n  <li>Carefully remove control unit.</li>\n  <li>Reverse procedure to install, noting the following:</li>\n  <ol type=\"a\">\n    <li><b>Torque</b> DSC control unit to hydraulic unit screws to 44 inch lbs.</li>\n    <li>Carry out programming/encoding.</li>\n    <li>Adjustment of steering angle sensor.</li>\n    <li>Brake line interchange inspection.</li>\n  </ol>\n</ol>"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('fc9289a3-1de9-4353-80d2-2e968e68f742', '59914b93-2d1a-4426-b22c-654d24866081', 'ABS Control Module R&R', 'P:562310703', 'Precautions', '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Control Module R&R</h2>\n<p>Prior to service, disconnect battery ground cable and isolate as required.</p><hr><p>Some original radios have a coded theft protection circuit. Obtain customer code number before disconnecting battery, removing fuses from underhood fuse/relay box or removing radio.</p>\n<ol type=\"1\">\n  <li>After servicing vehicle, connect power to radio and turn ignition switch to <q>1</q> position.</li>\n  <li>Press CODE. - - - - CODE is displayed.</li>\n  <li>Enter number using entry keys to.</li>\n  <li>Press SET/RES.</li>\n  <li>Turn ignition switch to <q>0</q> position.</li>\n  <li>If LED flashes for approximately 10 seconds, ensure hood and radio are properly closed and installed.</li>\n</ol>"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('b34a5caa-ddb0-4991-93a4-0d374640be43', '59914b93-2d1a-4426-b22c-654d24866081', 'ABS Control Module Relearn', 'P:564661784', NULL, '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Control Module Relearn</h2>\n<p>After replacing hydraulic control module control unit, it must be programmed to ensure proper function.</p>\n<ol type=\"1\">\n  <li>Obtain Progman ISTA/P programming system, or equivalent scan tool.</li>\n  <li>Connect battery charger.</li>\n  <li>Ensure battery voltage does not drop below 13 volts during programming.</li>\n  <li>To initiate programming utilizing ISTA/P, proceed as follows:</li>\n  <ol type=\"a\">\n    <li>Identify vehicle and read out control unit data.</li>\n    <li>Draw up and configure measures plan.</li>\n    <li>Prepare programming, export CBS/CKM data.</li>\n    <li>Carry out repair measures, replace control units, as required.</li>\n    <li>Identify vehicle again after repair. Update measures plan.</li>\n    <li>Perform programming.</li>\n    <li>Assess programming afterwards, import CBS/CKM data.</li>\n  </ol>\n  <li>To initiate programming utilizing Progman, proceed as follows:</li>\n  <ol type=\"a\">\n    <li>Proceed t"}]', NULL);
INSERT INTO procedures (id, vehicle_id, title, external_id, description, steps, category_id) VALUES ('0b2a4f9e-9314-4635-8b0b-42fc233ba1ad', '59914b93-2d1a-4426-b22c-654d24866081', 'ABS Hydraulic Control Unit R&R', 'P:543636101', 'Component Replacement', '[{"order":1,"text":"Imported content","html":"<h2 class=\"document-header\">ABS Hydraulic Control Unit R&R</h2>\n<ol type=\"1\">\n  <li>Remove lower section of microfilter housing, as required.</li>\n  <li>Remove upper center bulkhead sound insulation, as required.</li>\n  <li>Disconnect and position coolant expansion tank aside, as required.</li>\n  <li>Install pedal support to prevent fluid loss from master cylinder.</li>\n  <li>Remove lefthand side front wheel arch panel and underbody paneling to access hydraulic control unit, as required.</li>\n  <li>Remove underbody shield, as required.</li>\n  <li>Disconnect hydraulic control unit electrical connector.</li>\n  <li>Mark brake lines for installation reference.</li>\n  <li>Remove brake lines.</li>\n  <li>Remove mounting screws and hydraulic unit.</li>\n  <li>Reverse procedure to install. Bleed brake system as outlined in <q>Brake System Bleed.</q></li>\n</ol>"}]', NULL);
